/**
 * PuzzleApp.mjs — Puzzle system for lockpick-minigame
 * Puzzles: Sudoku, Sliding, Cipher, Simon Says
 * Difficulties: easy / medium / hard
 * GM triggers via toolbar → broadcasts via socket → opens on all clients
 */

export const PUZZLE_TYPES = [
  { id: 'sudoku',  label: '🔢 Судоку',                 icon: 'fas fa-th' },
  { id: 'sliding', label: '🟦 Sliding Puzzle (плитки)', icon: 'fas fa-border-all' },
  { id: 'cipher',  label: '🔤 Шифр (розшифруй слово)',  icon: 'fas fa-font' },
  { id: 'simon',   label: '🟢 Simon Says (послідовність)', icon: 'fas fa-circle' },
];

export const DIFFICULTIES = [
  { id: 'easy',   label: '🟢 Легка'   },
  { id: 'medium', label: '🟡 Середня' },
  { id: 'hard',   label: '🔴 Важка'   },
];

// ─── Dispatcher ──────────────────────────────────────────────────────────────

export function openPuzzle(type, difficulty, opts={}) {
  switch (type) {
    case 'sudoku':  return new SudokuPuzzle(difficulty, opts).render(true);
    case 'sliding': return new SlidingPuzzle(difficulty, opts).render(true);
    case 'cipher':  return new CipherPuzzle(difficulty, opts).render(true);
    case 'simon':   return new SimonPuzzle(difficulty, opts).render(true);
    default: ui.notifications.warn(`Unknown puzzle type: ${type}`);
  }
}

// Pre-generates puzzle state on GM side so it can be transmitted via socket
// and all clients (GM + players) see the exact same puzzle.
export function generatePuzzleOpts(type, difficulty, userOpts = {}) {
  switch (type) {
    case 'sudoku': {
      const { given, solution } = _makeSudokuPuzzle(difficulty);
      return { ...userOpts, given, solution };
    }
    case 'sliding': {
      const size  = difficulty === 'easy' ? 3 : difficulty === 'medium' ? 4 : 5;
      const tiles = _slidingGenerateTiles(size, difficulty);
      return { ...userOpts, tiles, size };
    }
    case 'simon': {
      const seqLen   = difficulty === 'easy' ? 4 : difficulty === 'medium' ? 6 : 9;
      const sequence = Array.from({ length: seqLen }, () => Math.floor(Math.random() * 4));
      return { ...userOpts, sequence };
    }
    default: return { ...userOpts };
  }
}

function _postSuccess(puzzleName) {
  ChatMessage.create({
    content: `<p>🎉 <strong>Головоломку "${puzzleName}" розгадано!</strong> Шлях відкрито.</p>`,
    type   : CONST.CHAT_MESSAGE_TYPES?.OOC ?? 1,
  });
}

// ═══════════════════════════════════════════════════════════════════════════════
// SUDOKU
// ═══════════════════════════════════════════════════════════════════════════════

// ─── Sudoku Generator ─────────────────────────────────────────────────────────

function _sudokuRandPerm(n) {
  const a = Array.from({ length: n }, (_, i) => i);
  for (let i = n - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function _generateSudokuGrid() {
  // Base valid grid via modular arithmetic (each row is a left-rotation of the previous)
  const base = [];
  for (let r = 0; r < 9; r++)
    for (let c = 0; c < 9; c++)
      base.push((r * 3 + Math.floor(r / 3) + c) % 9 + 1);

  // Valid transformations that preserve correctness:
  //   shuffle bands (rows of 3), shuffle rows within each band,
  //   shuffle stacks (cols of 3), shuffle cols within each stack,
  //   relabel digits.
  const bandOrder  = _sudokuRandPerm(3);
  const stackOrder = _sudokuRandPerm(3);
  const rowInBand  = [_sudokuRandPerm(3), _sudokuRandPerm(3), _sudokuRandPerm(3)];
  const colInStack = [_sudokuRandPerm(3), _sudokuRandPerm(3), _sudokuRandPerm(3)];
  const digitMap   = _sudokuRandPerm(9);

  const rowMap = [];
  for (let b = 0; b < 3; b++)
    for (let i = 0; i < 3; i++)
      rowMap.push(bandOrder[b] * 3 + rowInBand[bandOrder[b]][i]);

  const colMap = [];
  for (let b = 0; b < 3; b++)
    for (let i = 0; i < 3; i++)
      colMap.push(stackOrder[b] * 3 + colInStack[stackOrder[b]][i]);

  const grid = new Array(81);
  for (let r = 0; r < 9; r++)
    for (let c = 0; c < 9; c++)
      grid[r * 9 + c] = digitMap[base[rowMap[r] * 9 + colMap[c]] - 1] + 1;

  return grid;
}

function _sudokuCanPlace(board, idx, v) {
  const r = Math.floor(idx / 9), c = idx % 9;
  for (let i = 0; i < 9; i++) {
    if (board[r * 9 + i] === v || board[i * 9 + c] === v) return false;
  }
  const br = Math.floor(r / 3) * 3, bc = Math.floor(c / 3) * 3;
  for (let i = 0; i < 3; i++)
    for (let j = 0; j < 3; j++)
      if (board[(br + i) * 9 + (bc + j)] === v) return false;
  return true;
}

// Returns how many solutions exist, stopping early once limit is reached.
function _sudokuCountSolutions(board, limit = 2) {
  const idx = board.indexOf(0);
  if (idx === -1) return 1;
  let count = 0;
  for (let v = 1; v <= 9 && count < limit; v++) {
    if (_sudokuCanPlace(board, idx, v)) {
      board[idx] = v;
      count += _sudokuCountSolutions(board, limit - count);
      board[idx] = 0;
    }
  }
  return count;
}

function _makeSudokuPuzzle(difficulty) {
  const solution = _generateSudokuGrid();
  // easy: 46 clues — solvable in ~3-5 min with mostly naked singles
  // medium: 34 clues; hard: 26 clues
  const clues    = difficulty === 'easy' ? 46 : difficulty === 'medium' ? 34 : 26;
  const toRemove = 81 - clues;

  const given   = [...solution];
  const indices = _sudokuRandPerm(81);
  let removed   = 0;

  for (const idx of indices) {
    if (removed >= toRemove) break;
    const saved = given[idx];
    given[idx]  = 0;
    if (_sudokuCountSolutions([...given]) === 1) {
      removed++;
    } else {
      given[idx] = saved; // removing this cell creates ambiguity — keep it
    }
  }

  return { given, solution };
}

class SudokuPuzzle extends Application {
  constructor(difficulty, opts = {}) {
    super();
    this.difficulty  = difficulty;
    this._spectator  = opts.spectator ?? false;
    this._syncHandler = null;
    if (opts.given && opts.solution) {
      this.given    = opts.given;
      this.solution = opts.solution;
    } else {
      const generated = _makeSudokuPuzzle(difficulty);
      this.given    = generated.given;
      this.solution = generated.solution;
    }
    this.board    = [...this.given];
    this.selected = null;
    this.errors   = new Set();
  }

  static get defaultOptions() {
    return foundry.utils.mergeObject(super.defaultOptions, {
      id: 'lpm-sudoku', title: '🔢 Судоку', width: 420, height: 500,
      classes: ['lockpick-minigame', 'lpm-puzzle'],
    });
  }

  async _renderInner() {
    return $(`<div class="lpm-sudoku-wrap">
      <div class="lpm-sudoku-grid" id="lpm-sudoku-grid"></div>
      <div class="lpm-puzzle-hint">Клікни клітинку → введи цифру 1–9 (Delete або 0 — очистити)</div>
    </div>`);
  }

  activateListeners(html) {
    super.activateListeners(html);
    this._renderGrid(html);
    if (this._spectator) {
      this._syncHandler = (data) => {
        if (data.action === 'puzzleSync' && data.puzzleType === 'sudoku') {
          if (data.event === 'win') {
            if (this.element) this.element[0].innerHTML = `<div class="lpm-puzzle-win">🎉 Судоку розгадано!</div>`;
            setTimeout(() => this.close(), 2000);
            return;
          }
          this.board  = data.board;
          this.errors = new Set(data.errors);
          this._renderGrid($(this.element));
        }
      };
      game.socket.on(`module.${_lpmModuleId}`, this._syncHandler);
    } else {
      html[0].addEventListener('keydown', this._onKey.bind(this));
      html[0].setAttribute('tabindex', '0');
      html[0].focus();
    }
  }

  _renderGrid(html) {
    const grid = html.find('#lpm-sudoku-grid')[0];
    if (!grid) return;
    grid.innerHTML = '';
    for (let i = 0; i < 81; i++) {
      const cell = document.createElement('div');
      cell.className = 'lpm-sudoku-cell';
      const r = Math.floor(i / 9), c = i % 9;
      if (r % 3 === 0) cell.classList.add('border-top');
      if (c % 3 === 0) cell.classList.add('border-left');
      if (r === 8)     cell.classList.add('border-bottom');
      if (c === 8)     cell.classList.add('border-right');
      if (this.given[i])       cell.classList.add('given');
      else if (this.board[i])  cell.classList.add('player');
      if (i === this.selected) cell.classList.add('selected');
      if (this._spectator) {
        if (this.errors.has(i)) cell.classList.add('error');
        else if (!this.given[i] && this.board[i] && this.board[i] === this.solution[i])
          cell.classList.add('correct');
      }
      if (this.board[i]) cell.textContent = this.board[i];
      cell.dataset.idx = i;
      if (!this._spectator) {
        cell.addEventListener('click', () => { this.selected = i; this._renderGrid(html); });
      }
      grid.appendChild(cell);
    }
  }

  _onKey(e) {
    if (this.selected === null) return;
    const i = this.selected;
    if (this.given[i]) return;
    const html = $(this.element);

    if (e.key === 'Delete' || e.key === 'Backspace' || e.key === '0') {
      this.board[i] = 0;
      this.errors.delete(i);
    } else if (e.key >= '1' && e.key <= '9') {
      const n = parseInt(e.key);
      this.board[i] = n;
      if (n !== this.solution[i]) this.errors.add(i);
      else                         this.errors.delete(i);
      if (this._checkWin()) { this._win(); return; }
    } else if (e.key === 'ArrowRight') this.selected = Math.min(80, i + 1);
    else if (e.key === 'ArrowLeft')    this.selected = Math.max(0,  i - 1);
    else if (e.key === 'ArrowDown')    this.selected = Math.min(80, i + 9);
    else if (e.key === 'ArrowUp')      this.selected = Math.max(0,  i - 9);

    this._renderGrid(html);
    game.socket.emit(`module.${_lpmModuleId}`, {
      action: 'puzzleSync', puzzleType: 'sudoku',
      board: [...this.board], errors: [...this.errors],
    });
  }

  _checkWin() {
    return this.board.every((v, i) => v === this.solution[i]);
  }

  _win() {
    game.socket.emit(`module.${_lpmModuleId}`, { action: 'puzzleSync', puzzleType: 'sudoku', event: 'win' });
    const el = this.element[0];
    el.innerHTML = `<div class="lpm-puzzle-win">🎉 Судоку розгадано!</div>`;
    _postSuccess('Судоку');
    setTimeout(() => this.close(), 2000);
  }

  async close(opts = {}) {
    if (this._syncHandler) game.socket.off(`module.${_lpmModuleId}`, this._syncHandler);
    return super.close(opts);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// SLIDING PUZZLE
// ═══════════════════════════════════════════════════════════════════════════════

function _slidingValidMoves(blankIdx, size) {
  const r = Math.floor(blankIdx / size), c = blankIdx % size;
  const moves = [];
  if (r > 0)        moves.push(blankIdx - size);
  if (r < size - 1) moves.push(blankIdx + size);
  if (c > 0)        moves.push(blankIdx - 1);
  if (c < size - 1) moves.push(blankIdx + 1);
  return moves;
}

function _slidingGenerateTiles(size, difficulty) {
  const n = size * size;
  let tiles = Array.from({ length: n }, (_, i) => i);
  const shuffles = difficulty === 'easy' ? 40 : difficulty === 'medium' ? 80 : 150;
  let blankIdx = n - 1;
  for (let s = 0; s < shuffles; s++) {
    const moves = _slidingValidMoves(blankIdx, size);
    const next  = moves[Math.floor(Math.random() * moves.length)];
    [tiles[blankIdx], tiles[next]] = [tiles[next], tiles[blankIdx]];
    blankIdx = next;
  }
  return tiles;
}

class SlidingPuzzle extends Application {
  constructor(difficulty, opts = {}) {
    super();
    this.difficulty  = difficulty;
    this._spectator  = opts.spectator ?? false;
    this._syncHandler = null;
    this.size  = opts.size ?? (difficulty === 'easy' ? 3 : difficulty === 'medium' ? 4 : 5);
    this.tiles = opts.tiles ? [...opts.tiles] : _slidingGenerateTiles(this.size, difficulty);
    this.moves = 0;
  }

  static get defaultOptions() {
    return foundry.utils.mergeObject(super.defaultOptions, {
      id: 'lpm-sliding', title: '🟦 Sliding Puzzle', width: 440, height: 520,
      classes: ['lockpick-minigame', 'lpm-puzzle'],
    });
  }

  _validMoves(blankIdx) {
    return _slidingValidMoves(blankIdx, this.size);
  }

  async _renderInner() {
    return $(`<div class="lpm-sliding-wrap">
      <div class="lpm-sliding-moves">Ходів: <span id="lpm-moves">0</span></div>
      <div class="lpm-sliding-grid" id="lpm-sliding-grid"
           style="--sz:${this.size}"></div>
      <div class="lpm-puzzle-hint">Клікай плитки поряд з порожнім місцем</div>
    </div>`);
  }

  activateListeners(html) {
    super.activateListeners(html);
    this._renderGrid(html);
    if (this._spectator) {
      this._syncHandler = (data) => {
        if (data.action !== 'puzzleSync' || data.puzzleType !== 'sliding') return;
        if (data.event === 'win') {
          if (this.element) this.element[0].innerHTML = `<div class="lpm-puzzle-win">🎉 Розгадано!</div>`;
          setTimeout(() => this.close(), 2000);
          return;
        }
        this.tiles = data.tiles;
        this._renderGrid($(this.element));
      };
      game.socket.on(`module.${_lpmModuleId}`, this._syncHandler);
    }
  }

  _renderGrid(html) {
    const grid = html.find('#lpm-sliding-grid')[0];
    if (!grid) return;
    grid.innerHTML = '';
    const n = this.size;

    // Draw each tile as a canvas slice of the stone texture
    const TOTAL = n * n;
    const self  = this;

    const drawTiles = (img) => {
      self.tiles.forEach((val, idx) => {
        const tile = document.createElement('div');
        tile.className = val === 0 ? 'lpm-tile empty' : 'lpm-tile';
        if (val !== 0) {
          // Use canvas to render the stone slice for this tile number
          const canvas = document.createElement('canvas');
          canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%;border-radius:inherit;';
          const tileSize = Math.floor(Math.min(img.width, img.height) / n);
          // Source coords in original image (based on tile's GOAL position, not current)
          const goalIdx = val - 1;
          const gr = Math.floor(goalIdx / n);
          const gc = goalIdx % n;
          // We'll draw lazily after append using ResizeObserver
          tile.dataset.goalRow = gr;
          tile.dataset.goalCol = gc;
          tile.dataset.tileSize = tileSize;
          tile._stoneImg = img;
          tile._stoneCanvas = canvas;
          tile.style.position = 'relative';
          tile.style.overflow = 'hidden';

          const goalPos = val - 1;
          if (idx === goalPos) tile.classList.add('placed');

          tile.appendChild(canvas);

          // Number overlay
          const span = document.createElement('span');
          span.className = 'lpm-tile-num';
          span.textContent = val;
          tile.appendChild(span);

          if (!self._spectator) tile.addEventListener('click', () => self._move(idx, html));
        }
        grid.appendChild(tile);
      });

      // Draw stone after tiles are in DOM and have size
      requestAnimationFrame(() => {
        grid.querySelectorAll('.lpm-tile:not(.empty)').forEach(tile => {
          const c   = tile._stoneCanvas;
          if (!c) return;
          const w   = tile.offsetWidth  || 60;
          const h   = tile.offsetHeight || 60;
          c.width   = w;
          c.height  = h;
          const ctx = c.getContext('2d');
          const img = tile._stoneImg;
          const ts  = parseInt(tile.dataset.tileSize) || Math.floor(img.width / n);
          const gr  = parseInt(tile.dataset.goalRow);
          const gc  = parseInt(tile.dataset.goalCol);
          const sx  = gc * ts;
          const sy  = gr * ts;

          // Draw stone slice
          ctx.drawImage(img, sx, sy, ts, ts, 0, 0, w, h);

          // Darken a bit for better readability
          ctx.fillStyle = 'rgba(0,0,0,0.28)';
          ctx.fillRect(0, 0, w, h);

          // Bevel edges
          // Top highlight
          ctx.fillStyle = 'rgba(255,255,255,0.14)';
          ctx.fillRect(0, 0, w, 3);
          // Left highlight
          ctx.fillRect(0, 0, 3, h);
          // Bottom shadow
          ctx.fillStyle = 'rgba(0,0,0,0.55)';
          ctx.fillRect(0, h-3, w, 3);
          // Right shadow
          ctx.fillRect(w-3, 0, 3, h);

          // Inner bevel
          ctx.fillStyle = 'rgba(255,255,255,0.06)';
          ctx.fillRect(3, 3, w-6, 2);
          ctx.fillRect(3, 3, 2, h-6);

          // Placed tile: green tint overlay
          if (tile.classList.contains('placed')) {
            ctx.fillStyle = 'rgba(40,160,60,0.22)';
            ctx.fillRect(0, 0, w, h);
            ctx.strokeStyle = 'rgba(80,220,100,0.5)';
            ctx.lineWidth = 2;
            ctx.strokeRect(1, 1, w-2, h-2);
          }
        });
      });
    };

    // Load stone texture once, cache on grid element
    if (grid._stoneImg) {
      drawTiles(grid._stoneImg);
    } else {
      const img = new Image();
      img.onload = () => { grid._stoneImg = img; drawTiles(img); };
      img.src = 'data:image/jpeg;base64,';
    }

    html.find('#lpm-moves').text(this.moves);
  }

  _move(idx, html) {
    const blankIdx = this.tiles.indexOf(0);
    if (!this._validMoves(blankIdx).includes(idx)) return;
    [this.tiles[blankIdx], this.tiles[idx]] = [this.tiles[idx], this.tiles[blankIdx]];
    this.moves++;
    this._renderGrid(html);
    game.socket.emit(`module.${_lpmModuleId}`, {
      action: 'puzzleSync', puzzleType: 'sliding', tiles: [...this.tiles],
    });
    if (this._checkWin()) this._win();
  }

  _checkWin() {
    return this.tiles.every((v, i) => v === (i === this.tiles.length - 1 ? 0 : i + 1));
  }

  _win() {
    game.socket.emit(`module.${_lpmModuleId}`, { action: 'puzzleSync', puzzleType: 'sliding', event: 'win' });
    const el = this.element[0];
    el.innerHTML = `<div class="lpm-puzzle-win">🎉 Розгадано за ${this.moves} ходів!</div>`;
    _postSuccess('Sliding Puzzle');
    setTimeout(() => this.close(), 2000);
  }

  async close(opts = {}) {
    if (this._syncHandler) game.socket.off(`module.${_lpmModuleId}`, this._syncHandler);
    return super.close(opts);
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// CIPHER
// ═══════════════════════════════════════════════════════════════════════════════

// Fantasy alphabets mapping to English letters
const FANTASY_ALPHABETS = {
  infernal: {
    name: 'Інфернальна',
    // Each entry: fantasy char → English letter
    map: {
      '𐌰':'A','𐌱':'B','𐌲':'C','𐌳':'D','𐌴':'E','𐌵':'F','𐌶':'G','𐌷':'H',
      '𐌸':'I','𐌹':'J','𐌺':'K','𐌻':'L','𐌼':'M','𐌽':'N','𐌾':'O','𐌿':'P',
      '𐍀':'Q','𐍁':'R','𐍂':'S','𐍃':'T','𐍄':'U','𐍅':'V','𐍆':'W','𐍇':'X',
      '𐍈':'Y','𐍉':'Z'
    }
  },
  abyssal: {
    name: 'Безоднянська',
    map: {
      'ᚨ':'A','ᛒ':'B','ᚲ':'C','ᛞ':'D','ᛖ':'E','ᚠ':'F','ᚷ':'G','ᚺ':'H',
      'ᛁ':'I','ᛃ':'J','ᚲ':'K','ᛚ':'L','ᛗ':'M','ᚾ':'N','ᛟ':'O','ᛈ':'P',
      'ᚹ':'Q','ᚱ':'R','ᛊ':'S','ᛏ':'T','ᚢ':'U','ᚹ':'V','ᚹ':'W','ᛪ':'X',
      'ᚤ':'Y','ᛉ':'Z'
    }
  },
  elvish: {
    name: 'Ельфійська (Tengwar)',
    map: {
      'α':'A','β':'B','γ':'C','δ':'D','ε':'E','ζ':'F','η':'G','θ':'H',
      'ι':'I','κ':'J','λ':'K','μ':'L','ν':'M','ξ':'N','ο':'O','π':'P',
      'ρ':'Q','σ':'R','τ':'S','υ':'T','φ':'U','χ':'V','ψ':'W','ω':'X',
      'ϑ':'Y','ϕ':'Z'
    }
  }
};

const CIPHER_WORDS = {
  easy:   ['DOOR', 'LOCK', 'GOLD', 'FIRE', 'WOLF', 'MOON', 'STAR', 'KING', 'DARK', 'IRON'],
  medium: ['DRAGON', 'CASTLE', 'WIZARD', 'SHIELD', 'PORTAL', 'GOBLIN', 'SHADOW', 'TEMPLE'],
  hard:   ['DUNGEON MASTER', 'ANCIENT RUNES', 'FORBIDDEN TOME', 'DRAGONS HOARD'],
};

class CipherPuzzle extends Application {
  constructor(difficulty, opts={}) {
    super();
    this.difficulty  = difficulty;
    this._spectator  = opts.spectator ?? false;
    this._syncHandler = null;
    this.shift      = opts.shift ?? (3 + Math.floor(Math.random() * 8));

    // Word: custom or random
    if (opts.customWord && opts.customWord.trim()) {
      this.answer = opts.customWord.trim().toUpperCase();
    } else {
      const pool  = CIPHER_WORDS[difficulty];
      this.answer = pool[Math.floor(Math.random() * pool.length)];
    }

    // Language
    const langKey    = opts.lang ?? Object.keys(FANTASY_ALPHABETS)[0];
    this.langData    = FANTASY_ALPHABETS[langKey] ?? Object.values(FANTASY_ALPHABETS)[0];

    // Build reverse map: English → fantasy
    this.engToFan = {};
    for (const [fan, eng] of Object.entries(this.langData.map)) {
      if (!this.engToFan[eng]) this.engToFan[eng] = fan;
    }

    // Caesar-shift answer → intermediate
    this.caesarText  = this._caesar(this.answer, this.shift);
    // Convert intermediate → fantasy
    this.fantasyText = this.caesarText.split('').map(ch => ch===' '?' ':(this.engToFan[ch]??ch)).join('');
  }

  _caesar(text, shift) {
    return text.split('').map(ch => {
      if (ch===' ') return ' ';
      return String.fromCharCode(((ch.charCodeAt(0)-65+shift)%26)+65);
    }).join('');
  }

  static get defaultOptions() {
    return foundry.utils.mergeObject(super.defaultOptions, {
      id:'lpm-cipher', title:'🔤 Шифр', width:540, height:480,
      classes:['lockpick-minigame','lpm-puzzle'], resizable:true,
    });
  }

  async _renderInner() {
    const fanMap    = this.langData.map;
    const tableRows = Object.entries(fanMap).map(([fan,eng]) =>
      `<div class="lpm-cipher-pair"><span class="lpm-coded">${fan}</span><span class="lpm-plain">${eng}</span></div>`
    ).join('');
    const showTable = this.difficulty !== 'hard';

    if (this._spectator) {
      return $(`<div class="lpm-cipher-wrap">
        <div class="lpm-cipher-step">
          <div class="lpm-cipher-step-label">🔑 Відповідь (тільки для ДМ)</div>
          <div class="lpm-cipher-encoded" style="color:#4caf50;letter-spacing:6px;font-size:26px;">${this.answer}</div>
        </div>
        <div class="lpm-cipher-step">
          <div class="lpm-cipher-step-label">Зашифрований текст</div>
          <div class="lpm-cipher-encoded lpm-fantasy">${this.fantasyText}</div>
        </div>
        <div class="lpm-cipher-step">
          <div class="lpm-cipher-step-label">Гравець вводить:</div>
          <div id="lpm-cipher-player-input" style="
            min-height:42px; padding:10px 12px;
            background:#0e0e22; color:#eeeeff;
            border:2px solid #5555aa; border-radius:6px;
            font-size:20px; font-family:monospace; letter-spacing:5px;
            text-transform:uppercase;
          ">— очікування —</div>
        </div>
      </div>`);
    }

    return $(`<div class="lpm-cipher-wrap">
      <div class="lpm-cipher-step">
        <div class="lpm-cipher-step-label">Крок 1 — Розшифруй ${this.langData.name} алфавіт</div>
        <div class="lpm-cipher-encoded lpm-fantasy">${this.fantasyText}</div>
        ${showTable
          ? `<div class="lpm-cipher-sublabel">Таблиця ${this.langData.name} → Англійська:</div>
             <div class="lpm-cipher-table">${tableRows}</div>`
          : '<p class="lpm-puzzle-hint">Таблицю не надано — знайди закономірність.</p>'}
      </div>
      <div class="lpm-cipher-step">
        <div class="lpm-cipher-step-label">Крок 2 — Шифр Цезаря</div>
        <p class="lpm-puzzle-hint">${
          this.difficulty === 'hard'
            ? 'Зсув невідомий. Знайди закономірність.'
            : `Кожна буква зсунута на <strong>${this.shift}</strong> позицій вперед по алфавіту. Відніми ${this.shift} щоб отримати оригінал.`
        }</p>
      </div>

      <div style="margin-top:8px;">
        <div id="lpm-cipher-input"
             contenteditable="true"
             spellcheck="false"
             data-placeholder="Введи відповідь англійською…"
             style="
               display:block;
               width:calc(100% - 24px);
               min-height:40px;
               background:#0e0e22;
               color:#eeeeff;
               border:2px solid #5555aa;
               border-radius:6px;
               padding:10px 12px;
               font-size:18px;
               font-family:monospace;
               letter-spacing:4px;
               text-transform:uppercase;
               outline:none;
               box-sizing:border-box;
               cursor:text;
               margin-bottom:8px;
             "></div>
        <button id="lpm-cipher-check"
                style="
                  display:block;
                  width:100%;
                  padding:9px;
                  background:#2a2a6a;
                  color:#ccccff;
                  border:1px solid #5555aa;
                  border-radius:6px;
                  cursor:pointer;
                  font-size:14px;
                  font-weight:600;
                ">✓ Перевірити</button>
      </div>
      <div id="lpm-cipher-feedback" style="text-align:center;min-height:20px;margin-top:6px;font-size:13px;"></div>
    </div>`);
  }

  activateListeners(html) {
    super.activateListeners(html);

    if (this._spectator) {
      this._syncHandler = (data) => {
        if (data.action !== 'puzzleSync' || data.puzzleType !== 'cipher') return;
        const el = this.element?.[0]?.querySelector('#lpm-cipher-player-input');
        if (el) el.textContent = data.input || '—';
        if (data.event === 'win') {
          if (el) el.style.color = '#4caf50';
        }
      };
      game.socket.on(`module.${_lpmModuleId}`, this._syncHandler);
      return;
    }

    const divEl   = html.find('#lpm-cipher-input')[0];
    const checkEl = html.find('#lpm-cipher-check')[0];
    if (!divEl) return;

    const getText = () => divEl.innerText.trim().toUpperCase().replace(/[^A-Z ]/g,'');

    divEl.addEventListener('focus', () => divEl.style.borderColor = '#8888ff');
    divEl.addEventListener('blur',  () => divEl.style.borderColor = '#5555aa');

    const updatePH = () => {
      divEl.dataset.empty = divEl.innerText.trim() === '' ? '1' : '0';
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'puzzleSync', puzzleType: 'cipher', input: getText(),
      });
    };
    divEl.addEventListener('input', updatePH);
    updatePH();

    const _capture = (e) => {
      if (document.activeElement !== divEl) return;
      e.stopImmediatePropagation();
      if (e.type === 'keydown' && e.key === 'Enter') {
        e.preventDefault();
        this._check(getText(), html);
      }
    };
    window.addEventListener('keydown',  _capture, true);
    window.addEventListener('keyup',    _capture, true);
    window.addEventListener('keypress', _capture, true);

    Hooks.once('closeApplication', (app) => {
      if (app !== this) return;
      window.removeEventListener('keydown',  _capture, true);
      window.removeEventListener('keyup',    _capture, true);
      window.removeEventListener('keypress', _capture, true);
    });

    checkEl.addEventListener('click', () => this._check(getText(), html));
    setTimeout(() => divEl.focus(), 200);
  }

  _check(val, html) {
    const clean = val.toUpperCase().replace(/[^A-Z ]/g,'');
    if (clean === this.answer) {
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'puzzleSync', puzzleType: 'cipher', event: 'win', input: this.answer,
      });
      html[0].innerHTML = `<div class="lpm-puzzle-win">🎉 Шифр розгадано! Слово: ${this.answer}</div>`;
      _postSuccess('Шифр');
      setTimeout(() => this.close(), 2000);
    } else {
      const fb = html[0].querySelector('#lpm-cipher-feedback');
      if (fb) { fb.textContent = '❌ Невірно, спробуй ще.'; fb.style.color = '#ff6666'; }
    }
  }

  async close(opts = {}) {
    if (this._syncHandler) game.socket.off(`module.${_lpmModuleId}`, this._syncHandler);
    return super.close(opts);
  }
}

const SIMON_COLORS = [
  { id: 0, hex: '#2ecc71', dark: '#061409', border: '#1a6b3a', label: 'Алгіз'  },  // emerald
  { id: 1, hex: '#e74c3c', dark: '#160606', border: '#6b1a1a', label: 'Тіваз'  },  // ruby
  { id: 2, hex: '#3498db', dark: '#060e18', border: '#1a4a6b', label: 'Іса'    },  // sapphire
  { id: 3, hex: '#f39c12', dark: '#160e00', border: '#6b4800', label: 'Отала'  },  // amber
];

// Elder Futhark rune paths — coords in 0-1 space (wide, bold shapes)
const RUNES = [
  // Algiz (ᚨ) — protection: tall spine + two wide upward branches
  [ [0.50,0.08, 0.50,0.92],
    [0.50,0.28, 0.18,0.58],
    [0.50,0.28, 0.82,0.58] ],
  // Tiwaz (ᛏ) — victory: upward spear (V at top) + crossbar
  [ [0.50,0.08, 0.50,0.92],
    [0.50,0.08, 0.18,0.42],
    [0.50,0.08, 0.82,0.42],
    [0.22,0.64, 0.78,0.64] ],
  // Kenaz (ᚲ) — torch: spine + two right-pointing arms (like ᚲ)
  [ [0.50,0.08, 0.50,0.92],
    [0.50,0.26, 0.82,0.50],
    [0.50,0.50, 0.82,0.74] ],
  // Othala (ᛟ) — heritage: wide diamond + two splayed legs
  [ [0.50,0.10, 0.82,0.46],
    [0.82,0.46, 0.50,0.80],
    [0.50,0.80, 0.18,0.46],
    [0.18,0.46, 0.50,0.10],
    [0.18,0.46, 0.10,0.92],
    [0.82,0.46, 0.90,0.92] ],
];

const _lpmModuleId = 'lockpick-minigame';

class SimonPuzzle extends Application {
  constructor(difficulty, opts = {}) {
    super();
    this.difficulty = difficulty;
    this.seqLen   = difficulty === 'easy' ? 4 : difficulty === 'medium' ? 6 : 9;
    this.sequence = opts.sequence ? [...opts.sequence]
      : Array.from({ length: this.seqLen }, () => Math.floor(Math.random() * 4));
    this.step     = 0;
    this.phase    = 'ready';
    this._timeouts = [];
    this._html    = null;
    this._playerName = game.user.name;
  }

  static get defaultOptions() {
    return foundry.utils.mergeObject(super.defaultOptions, {
      id: 'lpm-simon', title: '🔮 Послідовність Рун', width: 420, height: 530,
      classes: ['lockpick-minigame', 'lpm-puzzle'],
    });
  }

  async _renderInner() {
    const grid = SIMON_COLORS.map(c => `
      <div class="lpm-simon-btn" data-id="${c.id}"
           style="background:${c.dark};border-color:${c.border}">
        <canvas class="lpm-rune-canvas" data-id="${c.id}"
                width="120" height="110"
                style="display:block;pointer-events:none;"></canvas>
        <span class="lpm-rune-label">${c.label}</span>
      </div>`).join('');

    if (this._spectator) {
      return $(`<div class="lpm-simon-wrap">
        <div class="lpm-simon-status" id="lpm-simon-status">👁 Очікування гравця…</div>
        <div class="lpm-simon-progress" id="lpm-simon-progress"></div>
        <div class="lpm-simon-grid" id="lpm-simon-grid" style="pointer-events:none">${grid}</div>
        <div id="lpm-simon-results" class="lpm-simon-results" style="display:none"></div>
        <div class="lpm-puzzle-hint">GM: спостереження в реальному часі</div>
      </div>`);
    }

    return $(`<div class="lpm-simon-wrap">
      <div class="lpm-simon-status" id="lpm-simon-status">🔮 Готовий почати?</div>
      <div class="lpm-simon-progress" id="lpm-simon-progress"></div>
      <div class="lpm-simon-grid" id="lpm-simon-grid">${grid}</div>
      <div id="lpm-simon-results" class="lpm-simon-results" style="display:none"></div>
      <button id="lpm-simon-ready" class="lpm-simon-ready-btn">
        ᚱ&nbsp;&nbsp;Готовий — почати!&nbsp;&nbsp;ᚱ
      </button>
      <div class="lpm-puzzle-hint">Запам'ятай послідовність → повтори руни у тому ж порядку</div>
    </div>`);
  }

  activateListeners(html) {
    super.activateListeners(html);
    this._html = html;
    requestAnimationFrame(() => this._drawAllRunes());

    if (this._spectator) {
      this._listenForResults();
      return;
    }

    // Rune buttons — player only
    html.find('.lpm-simon-btn').on('click', e => {
      if (this.phase !== 'input') return;
      const id = parseInt(e.currentTarget.dataset.id);
      this._flash(id, 220);
      this._handleInput(id);
    });

    html.find('#lpm-simon-ready').on('click', () => {
      html.find('#lpm-simon-ready').hide();
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'simonReady', playerName: this._playerName, userId: game.user.id,
      });
      this._startSequence();
    });
  }

  _listenForResults() {
    this._socketHandler = (data) => {
      if (data.action === 'simonResult') this._showGMResult(data);
      if (data.action === 'simonReady')  this._setStatus(`▶️ ${data.playerName} починає…`);
      if (data.action === 'puzzleSync' && data.puzzleType === 'simon') {
        if (data.event === 'flash')    this._flash(data.colorId, data.duration);
        if (data.event === 'progress') { this.step = data.step; this._updateProgress(); }
        if (data.event === 'status')   this._setStatus(data.text);
      }
    };
    game.socket.on(`module.${_lpmModuleId}`, this._socketHandler);
  }

  _showGMResult(data) {
    const el = this._html?.[0]?.querySelector('#lpm-simon-results');
    if (!el) return;
    el.style.display = 'block';
    const icon = data.success ? '✅' : '❌';
    const line = document.createElement('div');
    line.className = 'lpm-simon-result-row';
    line.innerHTML = `${icon} <strong>${data.playerName}</strong> — ${data.success ? 'Успішно!' : 'Провал'}`;
    el.appendChild(line);
  }

  _startSequence() {
    this.phase = 'watch';
    this._setStatus('🔮 Запам\u2019ятай послідовність…');
    game.socket.emit(`module.${_lpmModuleId}`, {
      action: 'puzzleSync', puzzleType: 'simon', event: 'status', text: '🔮 Гравець дивиться послідовність…',
    });
    this._updateProgress();

    let delay = 500;
    for (let i = 0; i < this.sequence.length; i++) {
      const id = this.sequence[i];
      this._t(() => this._flash(id, 550), delay);
      delay += 850;
    }
    this._t(() => {
      this.phase = 'input';
      this.step  = 0;
      this._setStatus('⚡ Твоя черга! Повтори послідовність рун.');
    }, delay + 300);
  }

  _flash(colorId, duration) {
    if (!this._html) return;
    const btn = this._html.find(`.lpm-simon-btn[data-id="${colorId}"]`)[0];
    if (!btn) return;
    const c = SIMON_COLORS[colorId];
    btn.style.borderColor = c.hex;
    btn.style.boxShadow   = `0 0 32px 10px ${c.hex}77, inset 0 0 18px ${c.hex}33`;
    btn.style.transform   = 'scale(1.08)';
    this._flashRune(colorId, true);
    setTimeout(() => {
      btn.style.borderColor = c.border;
      btn.style.boxShadow   = '';
      btn.style.transform   = '';
      this._flashRune(colorId, false);
    }, duration);
    // Sync flash to GM spectator
    if (!this._spectator) {
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'puzzleSync', puzzleType: 'simon', event: 'flash', colorId, duration,
      });
    }
  }

  _flashRune(colorId, lit) {
    const c = this._html?.[0]?.querySelector(`.lpm-rune-canvas[data-id="${colorId}"]`);
    if (!c) return;
    this._drawRune(c, colorId, lit);
  }

  _drawAllRunes() {
    if (!this._html) return;
    this._html[0].querySelectorAll('.lpm-rune-canvas').forEach(c => {
      const id = parseInt(c.dataset.id);
      this._drawRune(c, id, false);
    });
  }

  _drawRune(canvas, id, lit) {
    const w = canvas.offsetWidth  || 120;
    const h = canvas.offsetHeight || 110;
    canvas.width  = w;
    canvas.height = h;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, w, h);

    const segments = RUNES[id];
    const c        = SIMON_COLORS[id];

    ctx.save();
    ctx.lineCap  = 'round';
    ctx.lineJoin = 'round';

    const drawSegs = () => {
      for (const seg of segments) {
        ctx.beginPath();
        for (let j = 0; j < seg.length; j += 2)
          j === 0 ? ctx.moveTo(seg[j]*w, seg[j+1]*h) : ctx.lineTo(seg[j]*w, seg[j+1]*h);
        ctx.stroke();
      }
    };

    if (lit) {
      // Outer coloured glow pass
      ctx.shadowBlur  = 32;
      ctx.shadowColor = c.hex;
      ctx.lineWidth   = 9;
      ctx.strokeStyle = c.hex + '88';
      drawSegs();
      // Bright white core
      ctx.shadowBlur  = 20;
      ctx.shadowColor = c.hex;
      ctx.lineWidth   = 6;
      ctx.strokeStyle = '#ffffff';
      drawSegs();
      // Colour tint on top
      ctx.shadowBlur  = 0;
      ctx.lineWidth   = 3;
      ctx.strokeStyle = c.hex;
      drawSegs();
    } else {
      // Dim base — clearly visible but not lit
      ctx.shadowBlur  = 10;
      ctx.shadowColor = c.hex + '99';
      ctx.lineWidth   = 4.5;
      ctx.strokeStyle = 'rgba(255,255,255,0.55)';
      drawSegs();
      // Subtle colour tint
      ctx.shadowBlur  = 0;
      ctx.lineWidth   = 2;
      ctx.strokeStyle = c.hex + 'aa';
      drawSegs();
    }

    // Junction dots
    ctx.shadowBlur = lit ? 10 : 4;
    ctx.shadowColor = c.hex;
    ctx.fillStyle   = lit ? '#ffffff' : 'rgba(255,255,255,0.7)';
    for (const seg of segments) {
      ctx.beginPath();
      ctx.arc(seg[0]*w, seg[1]*h, lit ? 4 : 3, 0, Math.PI * 2);
      ctx.fill();
    }

    ctx.restore();
  }

  _handleInput(id) {
    if (id !== this.sequence[this.step]) {
      this.phase = 'done';
      this._setStatus('❌ Невірна руна! Послідовність порушена.');
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'puzzleSync', puzzleType: 'simon', event: 'status', text: '❌ Гравець помилився — провал.',
      });
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'simonResult', playerName: this._playerName, userId: game.user.id, success: false,
      });
      this._t(() => {
        if (this.element) this.element[0].innerHTML =
          `<div class="lpm-puzzle-win" style="color:var(--color-level-error,#e53935)">❌ Послідовність порушена!</div>`;
        setTimeout(() => this.close(), 2000);
      }, 900);
      return;
    }
    this.step++;
    this._updateProgress();
    game.socket.emit(`module.${_lpmModuleId}`, {
      action: 'puzzleSync', puzzleType: 'simon', event: 'progress', step: this.step,
    });

    if (this.step === this.sequence.length) {
      this.phase = 'done';
      this._setStatus('✨ Руни відгукнулись! Успіх!');
      // Notify GM
      game.socket.emit(`module.${_lpmModuleId}`, {
        action: 'simonResult',
        playerName: this._playerName,
        userId: game.user.id,
        success: true,
      });
      this._t(() => {
        if (this.element) this.element[0].innerHTML = `<div class="lpm-puzzle-win">✨ Послідовність рун відтворено!</div>`;
        _postSuccess('Послідовність рун');
        setTimeout(() => this.close(), 2000);
      }, 700);
    }
  }

  _setStatus(msg) {
    if (!this._html) return;
    this._html.find('#lpm-simon-status').html(msg);
  }

  _updateProgress() {
    if (!this._html) return;
    const dots = this.sequence.map((_, i) =>
      `<span class="lpm-simon-dot${i < this.step ? ' done' : ''}">${i < this.step ? '●' : '○'}</span>`
    ).join('');
    this._html.find('#lpm-simon-progress').html(dots);
  }

  _t(fn, ms) {
    const id = setTimeout(fn, ms);
    this._timeouts.push(id);
    return id;
  }

  async close(opts = {}) {
    this._timeouts.forEach(clearTimeout);
    if (this._socketHandler)
      game.socket.off(`module.${_lpmModuleId}`, this._socketHandler);
    return super.close(opts);
  }
}
